CREATE OR REPLACE FUNCTION stock.depot_read(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_data jsonb;
  v_actions jsonb;
  v_actif boolean;
BEGIN
  SELECT to_jsonb(d) || jsonb_build_object(
    'nb_articles', (SELECT count(DISTINCT m.article_id) FROM stock.mouvement m WHERE m.depot_id = d.id)::int
  )
  INTO v_data
  FROM stock.depot d
  WHERE d.id = p_id::int AND d.tenant_id = current_setting('app.tenant_id', true);

  IF v_data IS NULL THEN RETURN NULL; END IF;

  v_actif := (v_data->>'actif')::boolean;
  v_actions := '[]'::jsonb;

  IF v_actif THEN
    v_actions := v_actions || jsonb_build_array(
      jsonb_build_object('method', 'deactivate', 'uri', 'stock://depot/' || p_id || '/deactivate'),
      jsonb_build_object('method', 'inventory', 'uri', 'stock://depot/' || p_id || '/inventory')
    );
  ELSE
    v_actions := v_actions || jsonb_build_array(
      jsonb_build_object('method', 'activate', 'uri', 'stock://depot/' || p_id || '/activate')
    );
  END IF;

  v_actions := v_actions || jsonb_build_array(
    jsonb_build_object('method', 'delete', 'uri', 'stock://depot/' || p_id || '/delete')
  );

  RETURN v_data || jsonb_build_object('actions', v_actions);
END;
$function$;
COMMENT ON FUNCTION stock.depot_read(text) IS 'Read depot by id — returns full row with article count + HATEOAS actions';

CREATE OR REPLACE FUNCTION stock.depot_ui(p_slug text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_dep stock.depot;
  v_nb_articles int;
BEGIN
  -- List mode
  IF p_slug IS NULL THEN
    RETURN jsonb_build_object(
      'ui', pgv.ui_column(
        pgv.ui_heading(pgv.t('stock.nav_depots')),
        pgv.ui_table('depots', jsonb_build_array(
          pgv.ui_col('nom', pgv.t('stock.col_nom'), pgv.ui_link('{nom}', '/stock/depot/{id}')),
          pgv.ui_col('type', pgv.t('stock.col_type'), pgv.ui_badge('{type}')),
          pgv.ui_col('adresse', pgv.t('stock.col_adresse')),
          pgv.ui_col('nb_articles', pgv.t('stock.col_articles')),
          pgv.ui_col('actif', pgv.t('stock.col_actif'), pgv.ui_badge('{actif}'))
        ))
      ),
      'datasources', jsonb_build_object(
        'depots', pgv.ui_datasource('stock://depot', 20, true, 'nom')
      )
    );
  END IF;

  -- Detail mode
  SELECT * INTO v_dep FROM stock.depot WHERE id = p_slug::int AND tenant_id = current_setting('app.tenant_id', true);
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'not_found');
